import{z as t}from"zod";export const InjectionContextSchema=t.object({pinnedFactsBlock:t.string(),innerVoiceBlock:t.string(),contextBlock:t.string(),timelineBlock:t.string(),paceRecommendation:t.string(),totalBudget:t.number().int().min(0)}),AssembledPromptSchema=t.object({prompt:t.string(),sections:t.array(t.object({name:t.string(),content:t.string(),originalLength:t.number().int().min(0),truncated:t.boolean()})),truncated:t.boolean(),totalChars:t.number().int().min(0)});const h=.35,E=.1,g=.38,p=.1,B=.07,d=h+E+g+p+B;if(Math.abs(d-1)>1e-4)throw new Error(`InjectionPolicy budget allocation must sum to 1.0, got ${d}`);const T="\u3010\u6838\u5FC3\u8BBE\u5B9A\u3011",x="\u3010\u89D2\u8272\u5FC3\u58F0\u3011",A="\u3010\u76F8\u5173\u8BB0\u5FC6\u3011",k="\u3010\u65F6\u95F4\u7EBF\u3011",P="\u3010\u8282\u594F\u5EFA\u8BAE\u3011";export class InjectionPolicy{assemble(i){const o=InjectionContextSchema.parse(i),n=o.totalBudget,e=Math.floor(n*h),c=Math.floor(n*E),r=Math.floor(n*g),a=Math.floor(n*p),M=Math.floor(n*B),R=this.truncateSection(T,o.pinnedFactsBlock,e),S=this.truncateSection(x,o.innerVoiceBlock,c),_=this.truncateSection(A,o.contextBlock,r),f=this.truncateSection(k,o.timelineBlock,a),I=this.truncateSection(P,o.paceRecommendation,M),l=[R,S,_,f,I],u=[];for(const s of l)s.content.length!==0&&u.push(`${s.name}
${s.content}`);const m=u.join(`

`),N=l.some(s=>s.truncated),C=m.length;return{prompt:m,sections:l,truncated:N,totalChars:C}}truncateSection(i,o,n){const e=o.length;if(e<=n)return{name:i,content:o,originalLength:e,truncated:!1};if(n<=0)return{name:i,content:"",originalLength:e,truncated:e>0};const c="\u2026",r=n>=c.length?n-c.length:n,a=o.slice(0,r)+(n>=c.length?c:"");return{name:i,content:a,originalLength:e,truncated:!0}}}
